###############################################################################
# MedFabric
# Enterprise Healthcare Data & AI Platform
#
# File:
#     src/data_generation/build_raw_data.py
#
# Purpose:
#     Orchestrates the complete Raw layer data generation pipeline.
#
# Business Context:
#     The Raw layer is the foundational data platform layer. It contains
#     synthetic healthcare datasets generated by the MedFabric Synthetic Data
#     Engine.
#
#     This orchestrator is the single entry point that coordinates generation
#     of all 10 raw datasets in proper dependency order, validates outputs,
#     and generates comprehensive execution reporting.
#
# Inputs:
#     config/data_generation/generation.yaml
#     config/data_generation/*.yaml (per-generator configs)
#     reference/*/
#
# Outputs:
#     data/raw/*.parquet (10 datasets)
#     data/metadata/* (metadata for all datasets)
#     logs/pipeline/ (execution logs)
#
# Generated Datasets:
#     1. members.parquet
#     2. organizations.parquet
#     3. providers.parquet
#     4. facilities.parquet
#     5. enrollment.parquet
#     6. member_months.parquet
#     7. encounters.parquet
#     8. claim_headers.parquet
#     9. claim_lines.parquet
#     10. pharmacy.parquet
#     11. laboratory.parquet
#     12. sdoh.parquet
#
# Dependencies:
#     src.common.pipeline_context.create_pipeline_context
#     src.common.exception_manager.PipelineError
#     src.data_generation.generators.member_generator
#     src.data_generation.generators.organization_generator
#     src.data_generation.generators.provider_generator
#     src.data_generation.generators.facility_generator
#     src.data_generation.generators.enrollment_generator
#     src.data_generation.generators.member_months_generator
#     src.data_generation.generators.encounter_generator
#     src.data_generation.generators.claims_generator
#     src.data_generation.generators.pharmacy_generator
#     src.data_generation.generators.laboratory_generator
#     src.data_generation.generators.sdoh_generator
#
# Architectural Rules:
#     1. Use PipelineContext for all generator invocations.
#     2. Do not duplicate configuration loading. Pass context to generators.
#     3. Do not call context.logging.close() until all generators complete.
#     4. Track execution time for each generator and total pipeline time.
#     5. Validate all outputs before proceeding to next generator.
#     6. Generate comprehensive execution summary and lineage.
#     7. Propagate exceptions from generators without swallowing errors.
#
# Execution Order:
#     Phase 1 (Foundational Entities):
#         1. Members          (base person entity)
#         2. Organizations    (base enterprise entity)
#         3. Facilities       (base location entity)
#         4. Providers        (depends on Organizations)
#
#     Phase 2 (Relationships):
#         5. Enrollment       (depends on Members)
#         6. Member Months    (depends on Members, Enrollment)
#         7. SDOH            (depends on Members)
#
#     Phase 3 (Events):
#         8. Encounters       (depends on Facilities, Providers)
#         9. Claims           (depends on Encounters, Members)
#         10. Pharmacy        (depends on Members)
#         11. Laboratory      (depends on Members)
#
# Run Command:
#     python -m src.data_generation.build_raw_data
#
# Expected Output:
#     All 12 Raw layer datasets, metadata, and execution report.
#
