###############################################################################
# EXECUTION SUMMARY
###############################################################################


def generate_execution_summary(
    context,
    trackers: List[DatasetExecutionTracker],
    pipeline_start_time: datetime,
) -> Dict[str, Any]:
    """
    Generate comprehensive execution summary and report.

    Parameters
    ----------
    context:
        Active MedFabric PipelineContext.

    trackers:
        Execution tracking list for all datasets.

    pipeline_start_time:
        Pipeline start timestamp.

    Returns
    -------
    dict
        Execution summary.
    """
    logger = context.get_logger(MODULE_NAME)

    pipeline_end_time = datetime.now()
    pipeline_duration = (pipeline_end_time - pipeline_start_time).total_seconds()

    successful_datasets = [t for t in trackers if t.success]
    failed_datasets = [t for t in trackers if not t.success]

    total_rows = sum(t.row_count for t in successful_datasets)
    total_columns = sum(t.column_count for t in successful_datasets)

    summary: Dict[str, Any] = {
        "pipeline_name": "Raw Layer Data Generation",
        "execution_date": pipeline_start_time.isoformat(),
        "pipeline_duration_seconds": pipeline_duration,
        "total_datasets_attempted": len(trackers),
        "successful_datasets": len(successful_datasets),
        "failed_datasets": len(failed_datasets),
        "total_rows_generated": total_rows,
        "total_columns_generated": total_columns,
        "run_id": context.run_id,
        "pipeline_context": context.to_dict(),
        "dataset_executions": [t.to_dict() for t in trackers],
    }

    logger.info("=" * 80)
    logger.info("RAW LAYER EXECUTION SUMMARY")
    logger.info("=" * 80)
    logger.info("Pipeline Duration: %.2f seconds", pipeline_duration)
    logger.info("Successful Datasets: %s", len(successful_datasets))
    logger.info("Failed Datasets: %s", len(failed_datasets))
    logger.info("Total Rows Generated: %s", total_rows)
    logger.info("Total Columns Generated: %s", total_columns)

    for dataset_tracker in successful_datasets:
        logger.info(
            "  ✓ %s: %s rows, %s columns (%.2f seconds)",
            dataset_tracker.dataset_name,
            dataset_tracker.row_count,
            dataset_tracker.column_count,
            dataset_tracker.duration_seconds(),
        )

    for dataset_tracker in failed_datasets:
        logger.error(
            "  ✗ %s: FAILED - %s",
            dataset_tracker.dataset_name,
            dataset_tracker.error_message,
        )

    logger.info("=" * 80)

    return summary


###############################################################################
# ORCHESTRATION
###############################################################################


def run_raw_data_generation_pipeline(context) -> Dict[str, Any]:
    """
    Execute the complete Raw layer data generation pipeline.

    This is the master orchestrator that coordinates generation of all Raw
    layer datasets in proper dependency order.

    Parameters
    ----------
    context:
        Active MedFabric PipelineContext.

    Returns
    -------
    dict
        Execution summary with metrics for all datasets.

    Raises
    ------
    PipelineError
        Raised when any dataset generation fails and stop_on_error is enabled.
    """
    logger = context.get_logger(MODULE_NAME)
    pipeline_start_time = datetime.now()
    trackers: List[DatasetExecutionTracker] = []

    logger.info("Starting Raw Layer Data Generation Pipeline")
    logger.info("Pipeline Run ID: %s", context.run_id)

    try:
        # Phase 1: Foundational Entities
        logger.info("=" * 80)
        logger.info("PHASE 1: Foundational Entities")
        logger.info("=" * 80)

        execute_member_generation(context, trackers)
        execute_organization_generation(context, trackers)
        execute_facility_generation(context, trackers)
        execute_provider_generation(context, trackers)

        # Phase 2: Relationship Entities
        logger.info("=" * 80)
        logger.info("PHASE 2: Relationship Entities")
        logger.info("=" * 80)

        execute_enrollment_generation(context, trackers)
        execute_sdoh_generation(context, trackers)

        # Phase 3: Event Entities
        # (Encounter, Claims, Pharmacy, Laboratory generators will be added)
        logger.info("=" * 80)
        logger.info("PHASE 3: Event Entities")
        logger.info("=" * 80)
        logger.info("(Encounter, Claims, Pharmacy, Laboratory generation)")
        logger.info("(To be implemented by respective generators)")

        # Generate execution summary
        logger.info("=" * 80)
        logger.info("GENERATING EXECUTION SUMMARY")
        logger.info("=" * 80)

        summary = generate_execution_summary(context, trackers, pipeline_start_time)

        return summary

    except Exception as error:
        logger.exception("Raw data generation pipeline failed.")
        raise PipelineError("Raw data generation pipeline failed.") from error


def main() -> None:
    """
    Main entry point for Raw layer data generation.

    Run Command
    -----------
    python -m src.data_generation.build_raw_data
    """
    context = create_pipeline_context()
    logger = context.get_logger(MODULE_NAME)

    try:
        context.logging.start_step(STEP_NAME)

        summary = run_raw_data_generation_pipeline(context)

        context.logging.end_step(STEP_NAME)

        logger.info("Raw layer data generation pipeline completed successfully.")

        print("\n" + "=" * 80)
        print("RAW LAYER DATA GENERATION COMPLETED")
        print("=" * 80)
        print(f"Pipeline Duration: {summary['pipeline_duration_seconds']:.2f} seconds")
        print(f"Successful Datasets: {summary['successful_datasets']}")
        print(f"Failed Datasets: {summary['failed_datasets']}")
        print(f"Total Rows Generated: {summary['total_rows_generated']}")
        print("=" * 80 + "\n")

    except Exception as error:
        context.logging.log_exception(error, "Raw data generation pipeline failed.")
        logger.exception("Raw data generation pipeline failed.")
        raise PipelineError("Raw data generation pipeline failed.") from error

    finally:
        context.logging.close()


if __name__ == "__main__":
    main()
